"""HLD Key Technologies: API Gateway, Cassandra, DynamoDB — 20 deep MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def api_gateway_lesson() -> Lesson:
    return Lesson(id="hld-api-gateway", number=119, title="API Gateway",
        focus=("routing","rate limiting","auth","protocol translation","service mesh","Kong/AWS"),
        overview="API Gateways are the front door of microservices. Know routing, auth, rate limiting, and protocol translation.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("gw-1","What is an API Gateway?","medium",("api-gateway",),("A CDN","A load balancer only","A single entry point for microservices handling routing, auth, rate limiting, and protocol translation","A database proxy"),2,"API Gateways centralize cross-cutting concerns: auth, rate limiting, monitoring, protocol translation."),
        quiz("gw-2","What is the difference between an API Gateway and a load balancer?","hard",("api-gateway",),("LB is more feature-rich","Same thing","Gateway doesn't route","LB distributes traffic; API Gateway adds intelligent routing, auth, rate limiting, request/response transformation"),3,"L7 LB overlaps with Gateway but Gateway adds API-specific features like auth, throttling, and versioning."),
        quiz("gw-3","What is request routing in an API Gateway?","medium",("api-gateway",),("DNS routing","A database feature","Directing requests to the correct microservice based on URL path, headers, or query parameters","A caching strategy"),2,"/users → user-service, /orders → order-service. Path-based routing is most common."),
        quiz("gw-4","How does an API Gateway handle authentication?","medium",("api-gateway",),("Each service authenticates","Uses basic auth only","It doesn't","Validates JWT/API keys at the gateway, so individual services don't need auth logic"),3,"Gateway validates tokens once, adds user context to headers, forwards to services. Single auth point."),
        quiz("gw-5","What is rate limiting at the API Gateway level?","medium",("api-gateway",),("No rate limiting","A CDN feature","Enforcing request quotas per client/API key at the entry point before requests reach services","A database feature"),2,"Gateway rate limiting protects all downstream services. Uses token bucket or sliding window."),
        quiz("gw-6","What is protocol translation in an API Gateway?","hard",("api-gateway",),("A network feature","A database feature","No translation needed","Converting between protocols: HTTP REST externally ↔ gRPC/Thrift internally between microservices"),3,"Clients use REST/HTTP; internal services use gRPC for performance. Gateway bridges the protocols."),
        quiz("gw-7","What is the difference between Kong and AWS API Gateway?","hard",("api-gateway",),("Kong is AWS-only","AWS is self-hosted","Identical","Kong: self-hosted, Lua plugins, highly customizable. AWS: managed, Lambda integration, pay-per-request"),3,"Kong: open-source, runs anywhere. AWS API Gateway: managed, serverless-friendly, but AWS-locked."),
        quiz("gw-8","What is request aggregation (BFF pattern)?","hard",("api-gateway",),("A database JOIN","Caching requests","Backend-for-Frontend: gateway combines responses from multiple services into a single client response","A load balancing technique"),2,"Mobile client needs data from 3 services. BFF gateway makes 3 internal calls, combines, returns one response."),
        quiz("gw-9","What is circuit breaking at the Gateway level?","hard",("api-gateway",),("A hardware feature","A rate limiter","Gateway stops forwarding to a failing service after a threshold, returning fallback responses","A caching strategy"),2,"If user-service returns 500s, gateway trips circuit breaker → returns cached/default response → retries later."),
        quiz("gw-10","What is the service mesh vs API Gateway?","hard",("api-gateway",),("Gateway replaces mesh","Gateway handles north-south traffic (client→service); service mesh handles east-west (service→service)","Same thing","Mesh replaces gateway"),1,"Use both: API Gateway for external traffic, service mesh (Istio) for internal inter-service communication."),
        quiz("gw-11","What is request/response transformation?","medium",("api-gateway",),("A caching technique","Gateway modifies requests (add headers, change body format) or responses (filter fields, change status codes)","No transformation","A proxy feature"),1,"Transform legacy service responses to match API contract without changing the service."),
        quiz("gw-12","What is API throttling vs rate limiting?","medium",("api-gateway",),("Throttling is faster","Rate limiting caps requests per time window; throttling queues excess requests and processes them later","Rate limiting queues","Same thing"),1,"Rate limit: reject excess. Throttle: queue excess. Choose based on client expectations."),
        quiz("gw-13","How does an API Gateway handle versioning?","medium",("api-gateway",),("Changes the URL","It doesn't","Routes /v1/* to old service and /v2/* to new service, enabling gradual migration","Uses different ports"),2,"Gateway-based versioning: route by path prefix, header (Accept-Version), or query param."),
        quiz("gw-14","What is canary deployment via API Gateway?","hard",("api-gateway",),("Route a small percentage of traffic to a new service version, gradually increasing if healthy","A rollback strategy","A testing tool","A full deployment"),0,"Canary: 1% traffic → new version. Monitor errors/latency. Gradually increase to 100% or rollback."),
        quiz("gw-15","What is the fan-out pattern at the Gateway?","hard",("api-gateway",),("One client request triggers parallel calls to multiple services, results aggregated before responding","A caching pattern","A database pattern","A single service call"),0,"Gateway fans out to user-service, product-service, recommendation-service in parallel, aggregates results."),
        quiz("gw-16","What are the security features of an API Gateway?","medium",("api-gateway",),("SSL termination, JWT validation, OAuth2 flows, IP whitelisting, CORS handling, and WAF integration","Only SSL","None","Only auth"),0,"Centralized security: one place to enforce all security policies before traffic reaches services."),
        quiz("gw-17","What is the single point of failure risk with API Gateways?","hard",("api-gateway",),("Services still work","It's always redundant","No risk","If the gateway goes down, all services become unreachable — mitigate with redundancy and multi-zone deployment"),3,"Deploy gateway in multiple AZs with health checks. Use DNS failover between gateway instances."),
        quiz("gw-18","What is gRPC-Web and how does the API Gateway help?","hard",("api-gateway",),("A CDN feature","A database protocol","A JavaScript framework","Browsers can't use gRPC natively; the gateway translates HTTP/1.1 to gRPC, enabling browser-to-gRPC communication"),3,"Gateway as gRPC-Web proxy: browser sends HTTP → gateway converts to gRPC → forwards to service."),
        quiz("gw-19","What is the difference between edge and internal API Gateways?","hard",("api-gateway",),("Edge: handles external client traffic (auth, rate limiting). Internal: handles service-to-service routing (lighter)","Internal is external","Edge is simpler","Same thing"),0,"Edge gateway is security-heavy. Internal gateway/mesh is performance-focused with less overhead."),
        quiz("gw-20","What is API composition pattern?","hard",("api-gateway",),("Gateway calls multiple services and composes a single API response — replaces distributed JOINs","A caching strategy","A database pattern","A load balancing technique"),0,"Instead of clients making 5 calls, gateway makes 5 internal calls and returns one composed response."),
    ))

def cassandra_lesson() -> Lesson:
    return Lesson(id="hld-cassandra", number=120, title="Cassandra",
        focus=("partition key","clustering columns","consistency levels","compaction","gossip","SSTable"),
        overview="Cassandra is designed for massive write throughput and linear scalability. Know its data model and internals.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("cass-1","What is Cassandra's data model based on?","hard",("cassandra",),("Graph nodes","Partition key + clustering columns — queries MUST include the partition key","Relational tables","JSON documents"),1,"Design around query patterns. Partition key determines data placement; clustering columns sort within."),
        quiz("cass-2","What is a partition key in Cassandra?","hard",("cassandra",),("An index","A sort key","The column(s) whose hash determines which node stores the data — defines data distribution","A primary key"),2,"Choosing a good partition key is the single most important Cassandra design decision."),
        quiz("cass-3","What are clustering columns?","hard",("cassandra",),("Partition columns","Index columns","Foreign keys","Columns that define sort order within a partition — enabling range queries within the partition"),3,"Clustering columns: ORDER BY within a partition. E.g., PRIMARY KEY (user_id, created_at) sorts by time."),
        quiz("cass-4","What is Cassandra's consistency model?","hard",("cassandra",),("Always strong","Same as PostgreSQL","Eventually consistent only","Tunable per query: ONE (fast, stale), QUORUM (balanced), ALL (slow, consistent)"),3,"Tunable consistency: choose per operation. QUORUM = majority of replicas respond."),
        quiz("cass-5","What is the gossip protocol in Cassandra?","hard",("cassandra",),("A query protocol","A replication mechanism","A consensus algorithm","Peer-to-peer protocol where nodes periodically exchange cluster state (membership, health)"),3,"Gossip: no central coordinator. Nodes learn about each other through periodic state exchanges."),
        quiz("cass-6","What is an SSTable in Cassandra?","hard",("cassandra",),("A cache","A database table","Sorted String Table: an immutable on-disk file of key-value pairs, created when memtable flushes","A log file"),2,"Write path: memtable (memory) → flush → SSTable (disk). SSTables are immutable, merged by compaction."),
        quiz("cass-7","What is compaction in Cassandra?","hard",("cassandra",),("A replication step","Data compression","A backup process","Merging multiple SSTables to remove tombstones, deduplicate, and improve read performance"),3,"Compaction strategies: SizeTiered (write-heavy), Leveled (read-heavy), TimeWindow (time-series)."),
        quiz("cass-8","What is a tombstone in Cassandra?","hard",("cassandra",),("A crashed node","A backup marker","A marker for deleted data; kept until compaction removes it after gc_grace_seconds","An index entry"),2,"Tombstones propagate deletes across replicas. Too many tombstones slow reads — tune gc_grace_seconds."),
        quiz("cass-9","What is the write path in Cassandra?","hard",("cassandra",),("Direct to SSTable","Commit log (WAL) → memtable (memory) → flush to SSTable (disk) when memtable is full","Cache → DB","Direct to disk"),1,"Commit log ensures durability. Memtable accumulates writes. SSTable flush is sequential I/O."),
        quiz("cass-10","What is the read path in Cassandra?","hard",("cassandra",),("From cache only","Direct from SSTable","Bloom filter → key cache → partition index → SSTable → merge results from multiple SSTables","From memtable only"),2,"Bloom filter: quickly check if an SSTable might contain the key. Avoids unnecessary disk reads."),
        quiz("cass-11","What is Cassandra's replication strategy?","hard",("cassandra",),("Each partition replicated to N nodes (replication_factor). SimpleStrategy or NetworkTopologyStrategy","No replication","Synchronous replication","Master-slave"),0,"NetworkTopologyStrategy: specify replicas per datacenter. Data placed on nodes via consistent hashing."),
        quiz("cass-12","What is a materialized view in Cassandra?","hard",("cassandra",),("An automatically maintained copy of data with a different partition key for alternate query patterns","A manual copy","A cache","Same as SQL views"),0,"MVs let you query by different columns but have consistency overhead. Many teams prefer manual denormalization."),
        quiz("cass-13","Why doesn't Cassandra support JOINs?","hard",("cassandra",),("A design flaw","It does support JOINs","JOINs are too slow","Data is distributed across nodes — JOINs would require cross-node coordination, defeating the purpose"),3,"Cassandra philosophy: denormalize and duplicate data. Design tables around query patterns, not normalized models."),
        quiz("cass-14","What is lightweight transaction (LWT) in Cassandra?","hard",("cassandra",),("IF NOT EXISTS / IF conditions using Paxos consensus — linearizable but much slower than normal writes","An index","A regular transaction","A batch operation"),0,"LWTs provide linearizable consistency for critical operations (e.g., unique username check) at 4-10x latency cost."),
        quiz("cass-15","What is the repair process in Cassandra?","hard",("cassandra",),("Anti-entropy repair: compares Merkle trees across replicas, syncs any differences to ensure consistency","A backup process","A compaction step","Hardware repair"),0,"Run nodetool repair regularly (within gc_grace_seconds) to prevent resurrected tombstones."),
        quiz("cass-16","What are secondary indexes in Cassandra and when to avoid them?","hard",("cassandra",),("Indexes on non-partition columns — avoid for high-cardinality columns as they query all nodes","Use for all columns","They replace partition keys","Always use them"),0,"Secondary indexes: full cluster scan for high-cardinality. Use materialized views or denormalized tables instead."),
        quiz("cass-17","What is Cassandra's token ring?","hard",("cassandra",),("A network topology","A security token","Each node owns a range of tokens on a consistent hash ring; data is placed based on partition key hash","A session ring"),2,"Token range: Murmur3 hash of partition key determines which node(s) store the data."),
        quiz("cass-18","What is hinted handoff in Cassandra?","hard",("cassandra",),("A network feature","When a replica is temporarily down, another node stores the write as a hint and delivers it when the node recovers","A compaction step","A backup mechanism"),1,"Hinted handoff: temporary store-and-forward. Hints expire after a configurable period."),
        quiz("cass-19","What is the difference between Cassandra and ScyllaDB?","hard",("cassandra",),("ScyllaDB is Cassandra-compatible but written in C++ (vs Java), offering lower latency and better hardware utilization","ScyllaDB is slower","Same thing","Different data model"),0,"ScyllaDB: shard-per-core architecture, no JVM GC pauses. Drop-in Cassandra replacement with better perf."),
        quiz("cass-20","How do you model a time-series workload in Cassandra?","hard",("cassandra",),("No time-series support","Single table","One partition per record","Partition by entity + time bucket (e.g., sensor_id + day), cluster by timestamp — prevents unbounded partitions"),3,"Time bucketing: partition by (sensor_id, date). Limits partition size. Query by sensor + date range."),
    ))

def dynamodb_lesson() -> Lesson:
    return Lesson(id="hld-dynamodb", number=121, title="DynamoDB",
        focus=("partition key","sort key","GSI/LSI","capacity modes","streams","transactions"),
        overview="DynamoDB is AWS's managed NoSQL. Know its data model, capacity modes, and advanced features.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("ddb-1","What is DynamoDB's primary key model?","medium",("dynamodb",),("Partition key (hash) alone, or partition key + sort key (range) for composite keys","UUID only","Auto-increment ID","Same as SQL"),0,"Partition key: data placement. Sort key: range queries within a partition. Simple or composite."),
        quiz("ddb-2","What is the difference between GSI and LSI?","hard",("dynamodb",),("LSI is global","GSI: different partition key, stored separately, eventually consistent. LSI: same partition key, different sort key, strongly consistent","GSI is local","Same thing"),1,"GSI: can query by any attribute. LSI: must share the table's partition key. LSI created at table creation only."),
        quiz("ddb-3","What is on-demand vs provisioned capacity?","medium",("dynamodb",),("On-demand is always cheaper","No difference","Provisioned is deprecated","On-demand auto-scales per request; provisioned requires pre-set RCU/WCU, cheaper for predictable workloads"),3,"On-demand: 6-7x more expensive per request but zero capacity planning. Provisioned with auto-scaling is common."),
        quiz("ddb-4","What is a DynamoDB Stream?","hard",("dynamodb",),("A query result","A Kafka topic","An ordered log of item-level changes (INSERT, MODIFY, DELETE) that can trigger Lambda functions","A backup feature"),2,"Streams enable CDC: react to data changes, build materialized views, replicate to other systems."),
        quiz("ddb-5","What is a hot partition in DynamoDB?","hard",("dynamodb",),("A temperature issue","A caching problem","A network issue","A partition receiving traffic exceeding its throughput limit due to uneven key distribution"),3,"DynamoDB limits throughput per partition (~3000 RCU, 1000 WCU). Hot partitions get throttled."),
        quiz("ddb-6","How does DynamoDB handle transactions?","hard",("dynamodb",),("Only single-item","TransactWriteItems / TransactGetItems: atomic operations across up to 100 items in multiple tables","Same as SQL transactions","No transactions"),1,"DynamoDB transactions: ACID across items. 2x cost of normal operations. Max 100 items per transaction."),
        quiz("ddb-7","What is the single-table design pattern?","hard",("dynamodb",),("Store all entity types in one table using composite keys (PK/SK) and overloaded GSIs for multiple access patterns","A SQL pattern","One table per entity","A backup strategy"),0,"Single-table: PK=USER#123, SK=PROFILE or SK=ORDER#456. GSI1PK=ORDER#456 for order lookups."),
        quiz("ddb-8","What is a DynamoDB RCU and WCU?","medium",("dynamodb",),("Memory units","Read Capacity Unit: one strongly consistent 4KB read/sec. Write Capacity Unit: one 1KB write/sec","Network units","CPU units"),1,"RCU: 4KB strongly consistent or 8KB eventually consistent per unit. WCU: 1KB per unit per second."),
        quiz("ddb-9","What is adaptive capacity in DynamoDB?","hard",("dynamodb",),("DynamoDB automatically redistributes unused throughput from cold partitions to hot ones","A replication mode","Manual capacity","A caching feature"),0,"Adaptive capacity partially mitigates hot partitions by borrowing unused throughput. Not a complete solution."),
        quiz("ddb-10","What is DynamoDB Accelerator (DAX)?","hard",("dynamodb",),("A database upgrade","A fully managed, in-memory cache for DynamoDB providing microsecond read latency","A CDN","A backup service"),1,"DAX: drop-in caching layer. Same API as DynamoDB. Microsecond reads for cached data."),
        quiz("ddb-11","What is the write sharding pattern in DynamoDB?","hard",("dynamodb",),("Add a random suffix to partition key to distribute writes (e.g., counter#1, counter#2, ..., counter#N)","Sharding tables","A read optimization","A backup strategy"),0,"Write sharding spreads hot keys across partitions. Read requires scatter-gather across N suffixed keys."),
        quiz("ddb-12","What is the difference between strongly and eventually consistent reads?","medium",("dynamodb",),("Same thing","Eventually is always correct","Strongly is eventually","Strongly consistent reads from the leader partition; eventually consistent reads may come from any replica"),3,"Eventually consistent: 2x throughput, might be stale. Strongly consistent: 1x throughput, always latest."),
        quiz("ddb-13","What is point-in-time recovery (PITR) in DynamoDB?","medium",("dynamodb",),("Continuous backups enabling restoration to any point within the last 35 days","Manual backups","A replication feature","A caching strategy"),0,"PITR: automatic continuous backups. Restore to any second in the last 35 days. No performance impact."),
        quiz("ddb-14","How does DynamoDB handle global tables?","hard",("dynamodb",),("Single region only","Read replicas only","Multi-region, multi-active replication with eventual consistency and last-writer-wins conflict resolution","Manual replication"),2,"Global tables: write anywhere, replicate everywhere. Conflicts resolved by last-writer-wins (timestamp)."),
        quiz("ddb-15","What are condition expressions in DynamoDB?","hard",("dynamodb",),("SQL WHERE clauses","A filter","Conditional writes: only proceed if a condition is met (e.g., attribute_not_exists for unique inserts)","An index type"),2,"Condition expressions enable optimistic locking: update only if version matches expected value."),
        quiz("ddb-16","What is the batch operations limit in DynamoDB?","medium",("dynamodb",),("BatchWriteItem: max 25 items, 16MB. BatchGetItem: max 100 items, 16MB","100 items","1000 items","No limit"),0,"Batch operations are not transactional (partial failures possible). Use transactions for atomicity."),
        quiz("ddb-17","What is the difference between Scan and Query in DynamoDB?","medium",("dynamodb",),("Query uses the partition key (efficient). Scan reads every item in the table (expensive)","Query reads all items","Same thing","Scan is faster"),0,"Always prefer Query. Scan reads entire table, consuming throughput proportional to table size."),
        quiz("ddb-18","What is DynamoDB's pricing model?","medium",("dynamodb",),("Per table","Fixed monthly fee","Pay per RCU/WCU (provisioned) or per request (on-demand), plus storage ($0.25/GB/month) and data transfer","Free tier only"),2,"Cost optimization: use provisioned with auto-scaling for predictable workloads, on-demand for spiky."),
        quiz("ddb-19","What is a sparse GSI in DynamoDB?","hard",("dynamodb",),("A GSI where not all items have the indexed attribute — only items with that attribute appear in the GSI","A compressed index","A full copy","A filtered index"),0,"Sparse GSI: index only items where attribute exists. Reduces GSI size and cost. Great for status-based queries."),
        quiz("ddb-20","How do you handle large items (>400KB) in DynamoDB?","hard",("dynamodb",),("Split across rows","Increase item size limit","Not possible","Store the large data in S3 and save the S3 reference URL in DynamoDB"),3,"DynamoDB max item: 400KB. For larger data: S3 for blob, DynamoDB for metadata and S3 pointer."),
    ))
